-- The code below is based on the SQL Dump of a QGIS Layer with patches that we have manually ceraeted for the project;
-- Note: You can disregard references to "public" below -- it is the default schema so including it into the query does not change anything;
DROP TABLE IF EXISTS "public"."patches" CASCADE;
BEGIN;
CREATE EXTENSION IF NOT EXISTS postgis; -- Make sure to add the PostGIS extension to work with geographical and geometric data;
CREATE TABLE "public"."patches"(
	patch_id VARCHAR(70),
    chokepoint VARCHAR(20) NULL,
    wkb_geometry geometry(MULTIPOLYGON, 4326),
	PRIMARY KEY (patch_id),
	FOREIGN KEY (chokepoint) REFERENCES chokepoints(chokepoint_name));
	
COMMIT;




